INSERT INTO public.photos VALUES (23218, 'Fin de fiestas 2018', 'Imagen capturada desde el puente de Hierro durante el tradicional broche a las Fiestas del Pilar del aâ”śâ–’o 2018, protagonizado por el espectâ”śĂ­culo pirotâ”śÂ®cnico que el domingo 14 de octubre y desde la Arboleda de Macanaz iluminâ”śâ”‚ el ribereâ”śâ–’o cielo ante decenas de miles de personas congregadas a pesar de unas previsiones meteorolâ”śâ”‚gicas poco propicias, que finalmente no se cumplieron. La empresa Pirotecnia Zaragozana se encarga de estos actos desde 1860, cuando los cohetes se lanzaban desde el Coso y la plaza de la Constituciâ”śâ”‚n. En la imagen, los fuegos se imponen sobre el râ”śÂˇo Ebro y el puente de Piedra.', 2018, 2018, 2018, 'Siglo XXI', 'CASCO HISTâ”śĂ´RICO', 41.65891700, -0.87845500, '0101000020E6100000EA3E00A94D1CECBFA4E36A6457D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50315056737.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50315056737.webp', 'https://www.flickr.com/photos/zaragozaantigua/50315056737/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23231, 'El Pilar 2030', 'Ilustraciâ”śâ”‚n de cubierta para el câ”śâ”‚mic "Pilar Ultimate" (2010), con guion de Jorge Asâ”śÂˇn y dibujos de Moratha. Representa el entorno del Pilar y el Ebro en el aâ”śâ–’o 2030, aâ”śâ–’o en el que se activan misteriosamente las bombas guardadas en el interior del templo. En el centro, un alienâ”śÂˇgena surge de la silueta de la Virgen del Pilar; a la derecha, una comandante de la "Interestelar Civil Guard". Fuente: moratha.blogspot.com', 2024, 2020, 2029, 'Siglo XXI', 'CASCO HISTâ”śĂ´RICO', 41.65684300, -0.87862700, '0101000020E6100000323ECC5EB61DECBFA3CD716E13D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40095343121.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40095343121.webp', 'https://www.flickr.com/photos/zaragozaantigua/40095343121/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23794, 'Vista del este 1930', 'Antâ”śâ”‚nio Passaporte no era un luso al uso, y dijo que para capturar una imagen, cuanto mâ”śĂ­s arriba, mejor. Y si habâ”śÂˇa que sacar brillo a una titulada "El Ebro y vista parcial", desde los 90 metros de altura de la torre de Santiago en el templo del Pilar, el panorama serâ”śÂˇa de lujo. Dicho y hecho, aquâ”śÂˇ queda el testimonio del râ”śÂˇo, sus dos riberas (la derecha, especialmente), y una vista parcial del "barrio de La Seo" y del Casco Histâ”śâ”‚rico: la plaza de La Seo, y la plaza del Pilar. A la derecha, la torre de la Magdalena, tal y como estaba rematada por entonces. Esto fue antes del Plan de Reforma Interior de 1939, que desbaratâ”śâ”‚ bastante unos aâ”śâ–’os despuâ”śÂ®s todo esto. Este Plan fue ideado para que el "despegue hacia la modernidad" no encontrara obstâ”śĂ­culos urbanâ”śÂˇsticos en la "ciudad histâ”śâ”‚rica", reiterando los argumentos que desde mediados del siglo XIX se esgrimâ”śÂˇan en muchas ciudades europeas: insalubridad, falta de condiciones higiâ”śÂ®nicas y, signo de los tiempos, abrir hueco al trâ”śĂ­fico rodado, que mira que no haber pensado en ello... Y todo generando notables plusvalâ”śÂˇas econâ”śâ”‚micas, por supuesto, que acabaron en los bolsillos de algunas personas, de cuyo nombre es mejor no acordarse.', 1930, 1930, 1930, 'Anos 30', 'CASCO HISTâ”śĂ´RICO', 41.65680900, -0.87930800, '0101000020E6100000B08EE3874A23ECBFF75B3B5112D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14850702434.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14850702434.webp', 'https://www.flickr.com/photos/zaragozaantigua/14850702434/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23799, 'El Pilar 1860', '"Zaragoza : Templo de Nuestras Seâ”śâ–’ora del Pilar". Una de las fotos mâ”śĂ­s antiguas del Pilar, con la inacabada torre de Santiago, la câ”śâ•‘pula del Coro, el arranque de la câ”śâ•‘pula central antes de ser recrecida unos aâ”śâ–’os despuâ”śÂ®s, y la câ”śâ•‘pula de la Santa Capilla rodeada de cuatro câ”śâ•‘pulas menores. Fuente visual: Charles Clifford, en Biblioteca Nacional de Espaâ”śâ–’a', 1860, 1860, 1860, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65758000, -0.87901200, '0101000020E6100000655419C6DD20ECBF7940D9942BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14917839470.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14917839470.webp', 'https://www.flickr.com/photos/zaragozaantigua/14917839470/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23801, 'Plaza del Pilar 1967', 'Archivo Municipal Zaragoza. Gerardo Sancho Ramo. 30/11/1967. "Fiesta de la Policâ”śÂˇa Armada en la Plaza del Pilar." Mâ”śĂ­s que fiesta, fiestorro nacional-catâ”śâ”‚lico-militarista. Imagen de la plaza del Pilar con la gris revista de los policâ”śÂˇas armados, a pie, y a equino. Al fondo, San Juan de los Panetes y por encima de la alargada sombra de los cipreses, la alargada sombra del instrumento de tortura romano que seâ”śâ–’ala el monumento a quienes ganaron la guerra 1936-1939. Una guerra que tuvo sus vencedores. Vaya que si los tuvo.', 1967, 1967, 1967, 'Anos 60', 'CASCO HISTâ”śĂ´RICO', 41.65663300, -0.87934600, '0101000020E610000010CAFB389A23ECBFB83CD68C0CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15079575658.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15079575658.webp', 'https://www.flickr.com/photos/zaragozaantigua/15079575658/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23806, 'Plaza del Pilar c.1941', 'Taxis en las traseras del Pilar. Fuente visual: Gerardo Sancho Ramo, Archivo Municipal Zaragoza. Referencia: ES. 50297. AM 04.01.02.11 Carpeta 23863', 1941, 1941, 1941, 'Anos 40', 'CASCO HISTâ”śĂ´RICO', 41.65665700, -0.87922800, '0101000020E6100000954737C2A222ECBF41D829560DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15295762328.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15295762328.webp', 'https://www.flickr.com/photos/zaragozaantigua/15295762328/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23808, 'El Pilar 1968', 'Vista aâ”śÂ®rea de la plaza del Pilar y el râ”śÂˇo Ebro en 1968. Fuente: www.facebook.com/photo.php?fbid=10203073944866386&set...', 1968, 1968, 1968, 'Anos 60', 'CASCO HISTâ”śĂ´RICO', 41.65674300, -0.87849300, '0101000020E61000004A7A185A9D1CECBF3F70952710D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15386061880.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15386061880.webp', 'https://www.flickr.com/photos/zaragozaantigua/15386061880/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23810, 'El Pilar 1987', 'Luis Mâ”śÂˇnguez. 1987. El trâ”śĂ­nsito del 1986 al 1987 trajo nieve, momento que captura esta imagen tomada, al natural, desde la torre de San Francisco de Borja, hacia la ribera derecha del Ebro, con visual de la nieve posada en câ”śâ•‘pulas, cupulillas y tejados de la ciudad. En las torres y câ”śâ•‘pulas del Pilar permanecen las jaculatorias luminosas instaladas a principios de los aâ”śâ–’os cincuenta, cuando se instalaron luces de neâ”śâ”‚n en los remates de la basâ”śÂˇlica que reproducâ”śÂˇan la estâ”śâ”‚lida jaculatoria dedicada a la Virgen del Pilar (â”¬Â˝Bendita y alabada sea la hora en que Marâ”śÂˇa Santâ”śÂˇsima vino en carne mortal a Zaragoza. Por siempre sea bendita y alabadaâ”¬â•—), versos entonados por las voces del Coro de Infantes del Pilar y emitidos desde 1940, por atronadora megafonâ”śÂˇa exterior, cada dâ”śÂˇa a las 09.00, a las 12.00 y a las 20.00h. Las jaculatorias visuales se retiraron, aâ”śâ–’os despuâ”śÂ®s. Las otras, perduran.', 1987, 1987, 1987, 'Anos 80', 'CASCO HISTâ”śĂ´RICO', 41.65727900, -0.87893800, '0101000020E6100000D2C5A6954220ECBF7EACE0B721D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15643746208.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15643746208.webp', 'https://www.flickr.com/photos/zaragozaantigua/15643746208/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23811, 'El Pilar 1907', '"Vue d''ensemble de Notre-Dame du Pilier", Lucien Roy, 1907. Desde el Puente de Piedra, imagen del templo del Pilar con la segunda torre ya terminada, pendiente sâ”śâ”‚lo de retirar el andamiaje de obra, y algunos de los edificios de la ribera (la Casa de los Infantes, el Palacio de los Marqueses de Ayerbe). El poste metâ”śĂ­lico seâ”śâ–’ala el lugar de paso del tranvâ”śÂˇa de la lâ”śÂˇnea de Circunvalaciâ”śâ”‚n, ya electrificada. Siguen pasando vehâ”śÂˇculos a tracciâ”śâ”‚n de sangre. Fuente: Sociâ”śÂ®tâ”śÂ® Franâ”śÂşaise d''Archâ”śÂ®ologie et Ministâ”śÂżre de la Culture (France) - Mâ”śÂ®diathâ”śÂżque de l''architecture et du patrimoine - diffusion RMN', 1907, 1907, 1907, 'Anos 1900', 'CASCO HISTâ”śĂ´RICO', 41.65682700, -0.87847600, '0101000020E6100000C8444AB3791CECBF9D103AE812D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15662709823.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15662709823.webp', 'https://www.flickr.com/photos/zaragozaantigua/15662709823/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23816, 'El Pilar mudâ”śÂ®jar 1668', 'El acta notarial levantada en 1668 con motivo de la demoliciâ”śâ”‚n del templo mudâ”śÂ®jar del Pilar es una detallada descripciâ”śâ”‚n del edificio que existâ”śÂˇa antes del actual templo barroco-clasicista. Su aspecto exterior serâ”śÂˇa muy similar a las iglesias de Santiago de Montalbâ”śĂ­n, y San Pedro de Teruel: en ladrillo, una â”śâ•‘nica nave, capillas laterales entre los gruesos contrafuertes, coro a los pies, poderosa torre, entrada por la fachada sur (la de la plaza), y un claustro cuadrangular anexo en el lado del Ebro con capillas laterales en dos de sus lados, y la Santa Capilla en su centro. En la imagen, vista desde la ribera del Ebro de la reconstrucciâ”śâ”‚n virtual del exterior (iglesia y claustro), separadas por un "muro antiguo de la ciudad", tal vez un paâ”śâ–’o de la antigua muralla romana. El 25 de julio de 1681 fue colocada la primera piedra del nuevo templo, y en 1718 estaba concluida la mitad occidental. Se procediâ”śâ”‚ entonces al traslado al nuevo altar mayor del Santâ”śÂˇsimo Sacramento, procediâ”śÂ®ndose inmediatamente al piqueteo de la anterior iglesia mudâ”śÂ®jar y el viejo claustro, al objeto de continuar las obras en la parte oriental del nuevo templo. Fuente: "La reconstrucciâ”śâ”‚n virtual del Pilar mudâ”śÂ®jar. Bases histâ”śâ”‚ricas y potencial didâ”śĂ­ctico", Mâ”¬Â¬ Pilar Rivero, IFC, 2014.', 1668, 1668, 1668, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65682700, -0.87847600, '0101000020E6100000C8444AB3791CECBF9D103AE812D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16078379708.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16078379708.webp', 'https://www.flickr.com/photos/zaragozaantigua/16078379708/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23820, 'Zaragoza 1844', '"Templo del Pilar", una vista desde la margen izquierda, en la arboleda de Macanaz. Fuente visual: "Recuerdos y Bellezas de Espaâ”śâ–’a. Obra destinada a dar a conocer sus monumentos, antigâ”śâ•ťedades y vistas pintorescas en lâ”śĂ­minas dibujadas del natural y litografiadas por F. J. Parcerisa, acompaâ”śâ–’adas de texto por P. Piferrer y J. M. Quadrado. Aragâ”śâ”‚n: Josâ”śÂ® Marâ”śÂˇa Quadrado. 1844."', 1844, 1844, 1844, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65888300, -0.87877900, '0101000020E6100000B22B2D23F51EECBFF871344756D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18936497886.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18936497886.webp', 'https://www.flickr.com/photos/zaragozaantigua/18936497886/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23825, 'Plaza del Pilar 1988', 'Foto Eduardo Zamarripa, 1988. Vista aâ”śÂ®rea de la plaza del Pilar de Zaragoza en 1988. Fuente: Aragâ”śâ”‚n desde el aire, Ministerio de Defensa, 1988.', 1988, 1988, 1988, 'Anos 80', 'CASCO HISTâ”śĂ´RICO', 41.65682700, -0.87847600, '0101000020E6100000C8444AB3791CECBF9D103AE812D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20309642472.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20309642472.webp', 'https://www.flickr.com/photos/zaragozaantigua/20309642472/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23827, 'Templo del Pilar 1907', 'Postal. "Colecciâ”śâ”‚n Patria y Fe nâ”śâ•‘m. 40, Zaragoza 1908 - Centenario de los Sitios", 1907. "Los aragoneses pelearon por amor a su Virgen tanto como por amor a su patria. Armâ”śĂ­banse de valor ante el altar de su Patrona y despuâ”śÂ®s de cada triunfo entonaban ante ella solemnes alabanzas. Los ancianos y los niâ”śâ–’os refugiâ”śĂ­banse allâ”śÂˇ durante los bombardeos, instalando sus camas junto al tabernâ”śĂ­culo. No obstante, en distintas ocasiones las bombas francesas perforaron las torres y las bâ”śâ”‚vedas." Fuente: www.pasapues.es/', 1907, 1907, 1907, 'Anos 1900', 'CASCO HISTâ”śĂ´RICO', 41.65682700, -0.87847600, '0101000020E6100000C8444AB3791CECBF9D103AE812D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20779959321.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20779959321.webp', 'https://www.flickr.com/photos/zaragozaantigua/20779959321/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23828, 'Mallorca y Zaragoza 1490', 'Detalle de una sarga (tela pintada) representando milagros de la Virgen del Pilar. Maestro de Luesia, sacristâ”śÂˇa mayor del Pilar, 1490. La imagen narra la peripecia de un rico matrimonio de Palma de Mallorca que rezaba a la Virgen del Pilar para tener hijos. Cuando les nace un varâ”śâ”‚n, deciden ir a Zaragoza para agradecer el favor. Durante el viaje, pierden al niâ”śâ–’o cuando cae del barco. Pese a todo, van al camarâ”śÂˇn dentro del claustro subterrâ”śĂ­neo del Pilar, y allâ”śÂˇ estâ”śĂ­, a los pies de la Virgen, su hijo vivo, que les cuenta que fue ella quien le salvâ”śâ”‚ y le llevâ”śâ”‚ hasta allâ”śÂˇ. Como limosna, entregan un arca de plata. A la izquierda, Palma de Mallorca; en el centro, momento en el que el niâ”śâ–’o cae de cabeza al mar; a la derecha, Zaragoza, con el hijo seâ”śâ–’alando a la Virgen. Sobre â”śÂ®sta vemos los arcos del claustro del Pilar mudâ”śÂ®jar, en su â”śâ•‘nica representaciâ”śâ”‚n conocida. Fuente: "El milagro de Calanda y otros favores extraordinarios de Nuestra Seâ”śâ–’ora del Pilar", Tomâ”śĂ­s Domingo y Ester Casorrâ”śĂ­n, ed. Comuniter, 2015.', 1490, 1490, 1490, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65689500, -0.87847900, '0101000020E61000000C21E7FD7F1CECBFF5F3A62215D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20949846723.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20949846723.webp', 'https://www.flickr.com/photos/zaragozaantigua/20949846723/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23833, 'Vista aâ”śÂ®rea 1954', 'Vista aâ”śÂ®rea del centro de Zaragoza en 1954. Fuente: AMZ, a travâ”śÂ®s de www.facebook.com/photo.php?fbid=10203685974269714&set...', 1954, 1954, 1954, 'Anos 50', 'CASCO HISTâ”śĂ´RICO', 41.65687900, -0.87860700, '0101000020E61000006B2C616D8C1DECBFF0366F9C14D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22298695011.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22298695011.webp', 'https://www.flickr.com/photos/zaragozaantigua/22298695011/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23834, 'Vista aâ”śÂ®rea Ebro 1986', 'Foto: Josâ”śÂ® Luis Pomarâ”śâ”‚n Vista aâ”śÂ®rea desde el este de Zaragoza del râ”śÂˇo Ebro a su paso por la ciudad. Fuente: Colecciâ”śâ”‚n Rafael Margalâ”śÂ®.', 1986, 1986, 1986, 'Anos 80', 'CASCO HISTâ”śĂ´RICO', 41.65687900, -0.87860700, '0101000020E61000006B2C616D8C1DECBFF0366F9C14D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22304117552.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22304117552.webp', 'https://www.flickr.com/photos/zaragozaantigua/22304117552/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23844, 'El Pilar 1904', 'Vista del templo del Pilar desde la ribera del Ebro en una imagen publicada en 1904, con la torre de Santiago (1715) ya recrecida. Fuente: Revista "La fiesta nacional", Barcelona, 1904.', 1904, 1904, 1904, 'Anos 1900', 'CASCO HISTâ”śĂ´RICO', 41.65682700, -0.87847600, '0101000020E6100000C8444AB3791CECBF9D103AE812D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24457587551.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24457587551.webp', 'https://www.flickr.com/photos/zaragozaantigua/24457587551/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23855, 'El Pilar c.1904', 'Cromolitografâ”śÂˇa editada por el librero local Cecilio Gasca para su colecciâ”śâ”‚n de imâ”śĂ­genes titulada "Aragâ”śâ”‚n", e impresa por Purger & Co. (Mâ”śâ•ťnchen) como tintada postal que captura la tâ”śÂˇpica fachada al râ”śÂˇo Ebro del templo metropolitano de El Pilar, en los pocos aâ”śâ–’os que mediaron entre la finalizaciâ”śâ”‚n del remate de la primera torre, y la erecciâ”śâ”‚n de la segunda. Fuente visual: www.delcampe.net/', 1904, 1904, 1904, 'Anos 1900', 'CASCO HISTâ”śĂ´RICO', 41.65684800, -0.87858500, '0101000020E61000007632384A5E1DECBFB438639813D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27251156345.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27251156345.webp', 'https://www.flickr.com/photos/zaragozaantigua/27251156345/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23857, 'Ministros negros 1940', 'Dentro del oficial y grandioso centenario diecinueve del fantâ”śĂ­stico empadronamiento de la virgen del Pilar en la ciudad, allâ”śĂ­ por el aâ”śâ–’o 40 de la era, un evento fue remarcadamente seâ”śâ–’alado por las crâ”śâ”‚nicas locales: la devota consagraciâ”śâ”‚n en el metropolitano del Pilar, en ceremonia conducida por el obispo de la colonia de Guinea Espaâ”śâ–’ola, de tres nuevos ministros del seâ”śâ–’or, con la exâ”śâ”‚tica particularidad de pertenecer a la "raza negra", indâ”śÂˇgena de esta colonia, lo que fue significado como "la mejor prueba de la fecunda labor misional que Espaâ”śâ–’a practica en aquellas regiones africanas, llevâ”śĂ­ndoles la luz de la Fe". Ante el altar mayor pilarista, de espaldas, arrodillados y deslumbrados, los tres nuevos ministros negros del seâ”śâ–’or. Fuente visual: Miguel Marâ”śÂˇn Chivite, revista "Aragâ”śâ”‚n".', 1940, 1940, 1940, 'Anos 40', 'CASCO HISTâ”śĂ´RICO', 41.65692700, -0.87845700, '0101000020E61000001827BEDA511CECBF016E162F16D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27450646770.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27450646770.webp', 'https://www.flickr.com/photos/zaragozaantigua/27450646770/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23859, 'El Pilar 1861', 'Foto del templo del Pilar desde la margen izquierda del Ebro, cuando todavâ”śÂˇa no tenâ”śÂˇa ni câ”śâ•‘pula central ni la primera torre terminada. Fuente: Mariano Jâ”śâ•‘dez y Ortiz. â”śĂĽlbum de Andrâ”śÂ®s Martâ”śÂˇn e Ipâ”śĂ­s Colecciâ”śâ”‚n Mariano Martâ”śÂˇn Casalderrey, Zaragoza.', 1861, 1861, 1861, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65692700, -0.87845700, '0101000020E61000001827BEDA511CECBF016E162F16D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28490108971.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28490108971.webp', 'https://www.flickr.com/photos/zaragozaantigua/28490108971/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23864, 'Elâ”śÂ®ctricas Reunidas 1966', 'Acciâ”śâ”‚n de 500 pesetas de Elâ”śÂ®ctricas Reunidas de Zaragoza, que comienza su actividad en 1911, al unirse varias industrias del sector. Entre 1952 y 1965, su presidente fue Josâ”śÂ® Sinuâ”śÂ®s, tambiâ”śÂ®n al frente de la Caja de Ahorros de Zaragoza. Estas dos entidades formaron parte del mismo conglomerado durante todo el siglo XX. En los aâ”śâ–’os 70 y 80, ERZ era la empresa con mayor volumen de facturaciâ”śâ”‚n en Aragâ”śâ”‚n. En 1999 es absorbida por el grupo Endesa, propiedad de una multinacional italiana. Encabezando el documento, una reproducciâ”śâ”‚n del templo del Pilar. Fuente visual: www.ebay.es', 1966, 1966, 1966, 'Anos 60', 'CASCO HISTâ”śĂ´RICO', 41.65685900, -0.87856700, '0101000020E6100000DD088B8A381DECBFA88AA9F413D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30167115373.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30167115373.webp', 'https://www.flickr.com/photos/zaragozaantigua/30167115373/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23872, 'Congreso Esperanto 1954', 'Cartel de la 15â”¬Â¬ Hispana Kongreso de Esperanto, celebrado en Zaragoza en julio de 1954. Incluye la estrella verde esperantista, el escudo de la ciudad y una vista del Pilar y el puente de Piedra. Fuente: www.bildarchivaustria.at/', 1954, 1954, 1954, 'Anos 50', 'CASCO HISTâ”śĂ´RICO', 41.65690700, -0.87858800, '0101000020E6100000BB0ED594641DECBFB9C1508715D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30871684811.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30871684811.webp', 'https://www.flickr.com/photos/zaragozaantigua/30871684811/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23874, 'Sindicato de Iniciativa 1929', 'Cartel del Sindicato de Iniciativa y Propaganda de Aragâ”śâ”‚n, representando una vista del Pilar desde la Seo, impreso en Litografâ”śÂˇa Portabella y diseâ”śâ–’ado por â”śĂ«mile Paul Champseix. Esta entidad se constituyâ”śâ”‚ como asociaciâ”śâ”‚n en 1925, para promover el turismo de la regiâ”śâ”‚n. Hasta 1936, tambiâ”śÂ®n es una fuerza de influencia polâ”śÂˇtica regeneracionista y regionalista. Fuente: Revista Aragâ”śâ”‚n Turâ”śÂˇstico y Monumental, junio de 2015.', 1929, 1929, 1929, 'Anos 20', 'CASCO HISTâ”śĂ´RICO', 41.65676300, -0.87848100, '0101000020E61000003909A52F841CECBF861C5BCF10D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30931050553.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30931050553.webp', 'https://www.flickr.com/photos/zaragozaantigua/30931050553/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23877, 'Coronaciâ”śâ”‚n canâ”śâ”‚nica 1905', '"Peregrinaciâ”śâ”‚n y solemne coronaciâ”śâ”‚n a N. Sâ”¬Â¬ del Pilar". Medalla diseâ”śâ–’ada por el escultor Carlos Palao y acuâ”śâ–’ada por los hermanos Faci, en el marco de la coronaciâ”śâ”‚n canâ”śâ”‚nica de la Virgen del Pilar, celebrada el 20 de mayo de 1905, que incluyâ”śâ”‚ celebraciones y una peregrinaciâ”śâ”‚n, entre el 19 de mayo y el 18 de junio. En el anverso se representa a Isabel la Catâ”śâ”‚lica, vestida de peregrina y representando a Espaâ”śâ–’a, postrada ante Zaragoza, que la recibe con el Pilar de fondo. En el reverso, estandarte insignia de la peregrinaciâ”śâ”‚n, con la Virgen del Pilar sobre el escudo del papa Pâ”śÂˇo X. Fuente visual: www.milanuncios.com', 1905, 1905, 1905, 'Anos 1900', 'CASCO HISTâ”śĂ´RICO', 41.65690700, -0.87854500, '0101000020E6100000E90E62670A1DECBFB9C1508715D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31012227463.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31012227463.webp', 'https://www.flickr.com/photos/zaragozaantigua/31012227463/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23878, 'Guâ”śÂˇa de Zaragoza 1928', 'Guâ”śÂˇa Oficial de Zaragoza 1928-1929. Sindicato de Iniciativa y Propaganda de Aragâ”śâ”‚n, 1928. Folleto turâ”śÂˇstico de reparto gratuito. La cubierta a color, firmada por Codin Hnos., representa las fiestas del Pilar, con la basâ”śÂˇlica deconstruida al fondo. Fuente: www.todocoleccion.net', 1928, 1928, 1928, 'Anos 20', 'CASCO HISTâ”śĂ´RICO', 41.65692300, -0.87850200, '0101000020E6100000170FEF39B01CECBFBF7E880D16D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31016396351.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31016396351.webp', 'https://www.flickr.com/photos/zaragozaantigua/31016396351/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23880, 'El Pilar 1954', 'Fantâ”śĂ­stica composiciâ”śâ”‚n empleada como recuerdo del Congreso Mariano del aâ”śâ–’o 1954, celebrado con ocasiâ”śâ”‚n del Centenario I del dogma catâ”śâ”‚lico de la Inmaculada (o Purâ”śÂˇsima) Concepciâ”śâ”‚n. Un descomunal Papa Pâ”śÂˇo XII, iluminado por la Virgen del Pilar, abre los brazos ante las multitudes que acuden a la basâ”śÂˇlica concatedral, fulminantemente recrecida en las dos torres recayentes a la ribera del Ebro. Dos fuentes gigantes refrescan la plaza, aun siendo octubre, cuya despejada perspectiva parece llegar hasta la plaza de Sas (antigua del Carbâ”śâ”‚n). Fuente visual: www.ebay.es/', 1954, 1954, 1954, 'Anos 50', 'CASCO HISTâ”śĂ´RICO', 41.65681400, -0.87852200, '0101000020E6100000DE205A2BDA1CECBF08C72C7B12D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31302905426.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31302905426.webp', 'https://www.flickr.com/photos/zaragozaantigua/31302905426/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23886, 'Coronaciâ”śâ”‚n Canâ”śâ”‚nica 1905', '"Medalla Oficial de la Coronaciâ”śâ”‚n de Ntra. Sra. del Pilar de Zaragoza". Agustâ”śÂˇn Querol, 1905. En el anverso, la Santâ”śÂˇsima Trinidad coronando a la Virgen con la propia corona canâ”śâ”‚nica, con el escudo de Zaragoza abajo a la izquierda. En el reverso, la Virgen acompaâ”śâ–’ada de â”śĂ­ngeles que cantan la jaculatoria "Bendita y alabada sea", y una representaciâ”śâ”‚n del puente de Piedra y el templo del Pilar. La coronaciâ”śâ”‚n canâ”śâ”‚nica de la Virgen del Pilar, celebrada el 20 de mayo de 1905, incluyâ”śâ”‚ celebraciones y una peregrinaciâ”śâ”‚n, entre el 19 de mayo y el 18 de junio. Fuente visual: www.todocoleccion.net', 1905, 1905, 1905, 'Anos 1900', 'CASCO HISTâ”śĂ´RICO', 41.65689100, -0.87852400, '0101000020E61000000B09185DDE1CECBFB404190115D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32046219460.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32046219460.webp', 'https://www.flickr.com/photos/zaragozaantigua/32046219460/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23887, 'Cincomarzada aâ”śâ–’os 30', 'Foto: Miguel Marâ”śÂˇn Chivite. Grupo de personas celebrando la Cincomarzada en la arboleda de Macanaz, un 5 de marzo de los aâ”śâ–’os treinta. Al fondo, el Pilar. Fuente: Heraldo de Aragâ”śâ”‚n.', 1930, 1930, 1939, 'Anos 30', 'CASCO HISTâ”śĂ´RICO', 41.65936000, -0.87948900, '0101000020E6100000C422861DC624ECBF312592E865D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32129094301.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32129094301.webp', 'https://www.flickr.com/photos/zaragozaantigua/32129094301/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23888, 'La novia del cierzo 1983', 'Segunda de las tres viâ”śâ–’etas dibujadas por Isidro Ferrer para el relato "La novia del Cierzo". En la ilustraciâ”śâ”‚n, Cierzo se cala el cachirulo y sopla sobre su novia, la ciudad de Zaragoza. Doâ”śâ–’a Niebla tiene que irse, por mâ”śĂ­s que se agarra a las torres del Pilar. Un ciudadano con paraguas vuela acongojado. Fuente: "Zaragoza nuestra ciudad", Ayuntamiento de Zaragoza, 1983.', 1983, 1983, 1983, 'Anos 80', 'CASCO HISTâ”śĂ´RICO', 41.65684300, -0.87861000, '0101000020E6100000AF08FEB7921DECBFA3CD716E13D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32148478516.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32148478516.webp', 'https://www.flickr.com/photos/zaragozaantigua/32148478516/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23892, 'Vista aâ”śÂ®rea Pilar c.1968', 'Vista aâ”śÂ®rea centrada el el Pilar, con el barrio de Jesâ”śâ•‘s al fondo. Fuente visual: foto Pedro Marco.', 1968, 1968, 1968, 'Anos 60', 'CASCO HISTâ”śĂ´RICO', 41.65684300, -0.87852400, '0101000020E61000000B09185DDE1CECBFA3CD716E13D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33697981745.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33697981745.webp', 'https://www.flickr.com/photos/zaragozaantigua/33697981745/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23894, 'El Pilar 1955', 'Con motivo de los fastos en torno al centenario diecinueve de la venida de la Virgen del Pilar en carne mortal a Zaragoza (1940), el pintor valenciano Ramâ”śâ”‚n Stolz Viciano fue encargado para restaurar las bâ”śâ”‚vedas iluminadas in illo tempore por Goya, Bayeu y Gonzâ”śĂ­lez Velâ”śĂ­zquez. El resultado satisfizo a la Junta de Obras y al Cabildo catedralicio, de modo que le encargaron pintar despuâ”śÂ®s la bâ”śâ”‚veda del Coro Mayor con una alegorâ”śÂˇa mural de "La Mâ”śâ•‘sica al servicio de la Divinidad" (1941). En 1952 recibiâ”śâ”‚ un nuevo llamado para pintar dos pequeâ”śâ–’os murales, el patriâ”śâ”‚tico "La rendiciâ”śâ”‚n de Granada" y el antropolâ”śâ”‚gico "El milagro de Calanda", y en 1955 fue requerido para iluminar la elâ”śÂˇptica câ”śâ•‘pula sobre el ingreso al Coro Mayor con el motivo "Regina Sacratissimi Rosarii", mediante la representaciâ”śâ”‚n de una solemne procesiâ”śâ”‚n del Rosario, por lo que esta câ”śâ•‘pula desde entonces suele ser denominada la câ”śâ•‘pula del Rosario. Para la realizaciâ”śâ”‚n de esta encomienda contâ”śâ”‚ con el refuerzo del pintor catalâ”śĂ­n Josâ”śÂ® Alfonso Cunâ”śÂˇ y su compaâ”śâ–’era Alicia Bravo, que son quienes aparecen en la imagen, sobre el andamiaje dispuesto para poder acceder a la altura del lienzo mural. Fuente visual: www.josecuni.eu/', 1955, 1955, 1955, 'Anos 50', 'CASCO HISTâ”śĂ´RICO', 41.65696500, -0.87874300, '0101000020E610000080D8D2A3A91EECBFEECEDA6D17D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35003474481.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35003474481.webp', 'https://www.flickr.com/photos/zaragozaantigua/35003474481/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23910, 'El Pilar 1778', 'Ilustraciâ”śâ”‚n contemporâ”śĂ­nea (1948) del templo del Pilar que hubiera resultado de hacerse segâ”śâ•‘n el proyecto de Ventura Rodrâ”śÂˇguez, irrealizado en buena parte. Destaca la vistosa soluciâ”śâ”‚n dada a la fachada del Coreto, a la izquierda, y el remate de las cuatro torres "bajas" de las esquinas. La presencia de las câ”śâ•‘pulas y cupulillas resulta anacrâ”śâ”‚nica, ya que fueron levantadas a mediados del siglo XIX. Tambiâ”śÂ®n lo es la ausencia de la manzana de viviendas que desde el Retiro Bajo y vertebrada por la calle del Pilar llegaba hasta la Puerta del â”śĂĽngel. Es lo que tiene hacer un dibujo cuando toda esa manzana habâ”śÂˇa sido derribada al comienzo de la dâ”śÂ®cada de los aâ”śâ–’os 40 del siglo XX para levantar sobre su solar la nueva Casa Consistorial.', 1778, 1778, 1778, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65697800, -0.87856200, '0101000020E61000006B44300E2E1DECBF8318E8DA17D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52526464307.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52526464307.webp', 'https://www.flickr.com/photos/zaragozaantigua/52526464307/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24212, 'Ferrocarril de Canfranc 1933', '"Ferrocarril de Canfranc a Valencia por Zaragoza. Medio siglo de constancia aragonesa. 1882-1933. Del continente al Mediterrâ”śĂ­neo por Aragâ”śâ”‚n y Valencia". Medalla conmemorativa de las cinco dâ”śÂ®cadas transcurridas desde el inicio de las obras del tren transpirenaico por Canfranc. La estaciâ”śâ”‚n internacional habâ”śÂˇa sido inaugurada en 1928, y la lâ”śÂˇnea fue clausurada en 1970, convirtiendo su reapertura en una reivindicaciâ”śâ”‚n que permanece durante otro medio siglo. En el anverso, una locomotora de vapor. En el reverso, el monolito situado en la frontera franco-espaâ”śâ–’ola del puerto de Somport, levantado en 1862; el Miguelete o torre campanario de la catedral de Valencia; y el Pilar de Zaragoza, tras el puente de Piedra. Fuente visual: www.todocoleccion.net', 1933, 1933, 1933, 'Anos 30', 'CASCO HISTâ”śĂ´RICO', 41.65685900, -0.87858400, '0101000020E6100000603E59315C1DECBFA88AA9F413D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38806332944.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38806332944.webp', 'https://www.flickr.com/photos/zaragozaantigua/38806332944/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24228, 'Ferias y fiestas 1882', 'Portada de una Guâ”śÂˇa de ferias y fiestas en Zaragoza de 1882, con reproducciâ”śâ”‚n de la Torre Nueva (derribada diez aâ”śâ–’os despuâ”śÂ®s), la estatua de Ramâ”śâ”‚n Pignatelli (notablemente adelgazado), el Puente de Piedra y el Pilar, y unos cabezudos. Fuente: Gigantes y Cabezudos en Aragâ”śâ”‚n, Ibercaja, 1990.', 1882, 1882, 1882, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65700500, -0.87865200, '0101000020E61000006A1492CCEA1DECBF7C2766BD18D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23643795533.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23643795533.webp', 'https://www.flickr.com/photos/zaragozaantigua/23643795533/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24237, 'Fiestas del Pilar 1934', '"De mi pueblo", cartel de las Fiestas del Pilar de 1934, obra de Guillermo Pâ”śÂ®rez Baylo. Al fondo, el puente del piedra y el Pilar. Se le atribuye un modernismo tardâ”śÂˇo. Lo que sâ”śÂˇ es evidente es el uso de los colores de la bandera de la Repâ”śâ•‘blica en la figura principal. Fuente visual: www.todocoleccion.net', 1934, 1934, 1934, 'Anos 30', 'CASCO HISTâ”śĂ´RICO', 41.65682700, -0.87858800, '0101000020E6100000BB0ED594641DECBF9D103AE812D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32515670212.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32515670212.webp', 'https://www.flickr.com/photos/zaragozaantigua/32515670212/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24732, 'Vista de la Margen Izquierda 1968', 'Ayuntamiento de Zaragoza. Gerardo Sancho Ramo. 18/05/1968. Vistas de la Margen Izquierda desde la torre de San Francisco de Borja del Pilar.', 1968, 1968, 1968, 'Anos 60', 'CASCO HISTâ”śĂ´RICO', 41.65723400, -0.87880400, '0101000020E6100000EB01F390291FECBFDEE8633E20D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14817000907.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14817000907.webp', 'https://www.flickr.com/photos/zaragozaantigua/14817000907/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24737, 'Fuente de la Princesa aâ”śâ–’os 30', '"Durante algo menos de 10 aâ”śâ–’os, la Fuente de la Princesa que estuvo antes en la actual Plaza de Espaâ”śâ–’a, fue montada con mâ”śĂ­s pena que gloria en la Arboleda de Macanaz de Zaragoza. La fuente no llegâ”śâ”‚ nunca a echar agua por sus caâ”śâ–’os. Miraba al Pilar hasta que fue trasladada al actual Parque Grande Josâ”śÂ® Antonio Labordeta." Mâ”śĂ­s informaciâ”śâ”‚n: tausiet.blogspot.com.es/2016/01/la-historia-errante-de-ne... Fuente: somoszaragoza.wordpress.com/2011/08/31/fuente-de-la-princ...', 1930, 1930, 1939, 'Anos 30', 'CASCO HISTâ”śĂ´RICO', 41.65907800, -0.87886200, '0101000020E6100000124F7633A31FECBFADC1FBAA5CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15180429201.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15180429201.webp', 'https://www.flickr.com/photos/zaragozaantigua/15180429201/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24766, 'Arboleda de Macanaz 1930', 'Foto: Archivo Heraldo de Aragâ”śâ”‚n. Rebaâ”śâ–’o de cabras con un grupo de personas en la orilla del Ebro, junto a la arboleda de Macanaz. Al fondo, el puente de Piedra. Fuente: www.facebook.com/photo.php?fbid=838460819509878&set=g...', 1930, 1930, 1930, 'Anos 30', 'CASCO HISTâ”śĂ´RICO', 41.65894200, -0.87963500, '0101000020E6100000BC57AD4CF825ECBFFDFA213658D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20708117216.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20708117216.webp', 'https://www.flickr.com/photos/zaragozaantigua/20708117216/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24767, 'Arboleda de Macanaz 1865', 'Plano de la arboleda de Macanaz, Antonio Berbegal, Zaragoza, 1865. Al norte, el camino de Ranillas. Al sur, el râ”śÂˇo Ebro. Se distingue el arbolado mediante distintos colores. Fuente: AMZ.', 1865, 1865, 1865, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65942800, -0.87907900, '0101000020E6100000593673486A21ECBF8908FF2268D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21033348365.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21033348365.webp', 'https://www.flickr.com/photos/zaragozaantigua/21033348365/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25060, 'La Pilar de Potosâ”śÂˇ 1954', '1954. La "Hermandad de Campeadores Hispâ”śĂ­nicos" entregâ”śâ”‚ una imagen de la Virgen del Pilar a la Iglesia de Santiago del Râ”śÂˇo, en la mejicana ciudad de San Luis de Potosâ”śÂˇ. El acto se hizo en el Monasterio de San Lorenzo de El Escorial. Se trataba de una talla del siglo XVII que pertenecâ”śÂˇa al periodista Emilio Alfaro, director de "La Hoja del Lunes de Zaragoza", que la entregâ”śâ”‚ para ser regalada. El Ayuntamiento de Zaragoza la vistiâ”śâ”‚ con el manto de la ciudad, sin coste aâ”śâ–’adido (lo pagâ”śâ”‚ la ciudad). Improvisada imagen de grupo, con el donante Emilio Alfaro (al fondo), la donada (en el centro), el receptor mejicano Francisco Salazar Hernâ”śĂ­ndez (izquierda), y el intermediario sacerdote indâ”śÂˇgena Alfonso D. Ruiz (derecha).', 1954, 1954, 1954, 'Anos 50', 'CASCO HISTâ”śĂ´RICO', 41.65675300, -0.87845000, '0101000020E6100000787AA52C431CECBF6346787B10D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14923345181.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14923345181.webp', 'https://www.flickr.com/photos/zaragozaantigua/14923345181/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25076, 'Sofâ”śÂˇa y Elena 1970', 'Foto: Luis Mompel. Sofâ”śÂˇa de Grecia sostiene a su hija Elena de Borbâ”śâ”‚n en el camarâ”śÂˇn de la Virgen del Pilar de Zaragoza, en 1970. Segâ”śâ•‘n rumor popular, el acceso de adultos a ese espacio estâ”śĂ­ vedado, con excepciones como la de Francisco Franco y esta seâ”śâ–’ora, que en la â”śÂ®poca formaba parte de su corte. Fuente: Archivo Heraldo de Aragâ”śâ”‚n.', 1970, 1970, 1970, 'Anos 70', 'CASCO HISTâ”śĂ´RICO', 41.65689500, -0.87847900, '0101000020E61000000C21E7FD7F1CECBFF5F3A62215D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21404068478.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21404068478.webp', 'https://www.flickr.com/photos/zaragozaantigua/21404068478/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25118, 'El Pilar 1976', 'Carlos Azagra. 1976. Colaboraciâ”śâ”‚n de Carlos Azagra para el Boletâ”śÂˇn de la "Asociaciâ”śâ”‚n de Cabezas de Familia" del Barrio de San Josâ”śÂ®. La basâ”śÂˇlica del Pilar como montaje con que los poderes econâ”śâ”‚micos, sociales y religioso-militares pretenden ocultar la realidad de una ciudad que echa humo.', 1976, 1976, 1976, 'Anos 70', 'CASCO HISTâ”śĂ´RICO', 41.65668300, -0.87844600, '0101000020E61000001DAA29C93A1CECBF6A6B44300ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15183105342.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15183105342.webp', 'https://www.flickr.com/photos/zaragozaantigua/15183105342/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25163, 'Arboleda de Macanaz c.1943', '"Paisaje". â”śĂ´leo sobre lienzo, Rafael Aguado Arnal, c.1940-1945. Representaciâ”śâ”‚n de la arboleda de Macanaz, con el puente de Piedra al fondo. Fuente: web.dpz.es/arscatalogi.es', 1943, 1943, 1943, 'Anos 40', 'CASCO HISTâ”śĂ´RICO', 41.65891100, -0.87854500, '0101000020E6100000E90E62670A1DECBFC2FC153257D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32118617263.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32118617263.webp', 'https://www.flickr.com/photos/zaragozaantigua/32118617263/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25171, 'El Pilar 1978', 'Ilustraciâ”śâ”‚n de Antonio Soteras publicada en el tercer y â”śâ•‘ltimo nâ”śâ•‘mero de la revista del Colectivo Zeta (1978). Muestra una metâ”śĂ­fora visual crâ”śÂˇtica con la sociedad zaragozana de la â”śÂ®poca. Con el templo del Pilar al fondo, un obrero custodiado por dos policâ”śÂˇas armados sostiene a la Virgen, que nutre a un burguâ”śÂ®s acomodado y a una baturra que representa las adocenadas fiestas locales. Este dibujo, variante de la tradicional iconografâ”śÂˇa de la pirâ”śĂ­mide social, asâ”śÂˇ como una fotografâ”śÂˇa en la contraportada que recuerda la â”śĂśltima Cena, fueron motivo de denuncia, que desembocâ”śâ”‚ en un juicio por escarnio a la religiâ”śâ”‚n catâ”śâ”‚lica al aâ”śâ–’o siguiente. La sentencia fue de cuatro aâ”śâ–’os de câ”śĂ­rcel. Mâ”śĂ­s informaciâ”śâ”‚n: www.zaragozarebelde.org/zeta-la-ultima-letra Fuente visual: Colecciâ”śâ”‚n particular de Antonio Altarriba.', 1978, 1978, 1978, 'Anos 70', 'CASCO HISTâ”śĂ´RICO', 41.65685400, -0.87850000, '0101000020E6100000E9263108AC1CECBF971FB8CA13D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33868573636.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33868573636.webp', 'https://www.flickr.com/photos/zaragozaantigua/33868573636/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25521, 'El Pilar c.1864', 'Imagen parcial de una placa estereoscâ”śâ”‚pica capturada desde la margen izquierda del râ”śÂˇo Ebro, y centrada en el Templo Metropolitano de Nuestra Seâ”śâ–’ora del Pilar, caracterizado exteriormente por la inacabada torre de Santiago, y cubierto por la câ”śâ•‘pula del Coro, el arranque de la câ”śâ•‘pula central, y la câ”śâ•‘pula de la Santa Capilla rodeada de cuatro câ”śâ•‘pulas menores. Si bien esta es una de las escasas imâ”śĂ­genes del Pilar antes de las obras de construcciâ”śâ”‚n de la gran câ”śâ•‘pula central, y de las cuatro câ”śâ•‘pulas que rodean al Coro, tal vez el valor aâ”śâ–’adido mâ”śĂ­s estimable aquâ”śÂˇ sea una pequeâ”śâ–’a vista lateral de la ribereâ”śâ–’a Puerta del â”śĂĽngel, que desde el puente de Piedra abrâ”śÂˇa el acceso a la ciudad por la calle de la Lonja, entre el Seminario Episcopal y la Casa del Ayuntamiento. Esta imagen, en una versiâ”śâ”‚n completa que se extiende por el puente de Piedra, e incluye la torre de Santiago del Pilar, fue luego incluida en el libro de viajes por Espaâ”śâ–’a de Edmondo De Amicis, realizado durante el reinado de Amadeo I de Saboya. Fuente visual: original de Ferrier et Soulier editada por J. Lâ”śÂ®vy et Câ”śÂˇa, en Zaragoza estereoscâ”śâ”‚pica, fotografâ”śÂˇa profesional y comercial 1850-1970, PUZ.', 1864, 1864, 1864, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65685400, -0.87850000, '0101000020E6100000E9263108AC1CECBF971FB8CA13D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34598416160.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34598416160.webp', 'https://www.flickr.com/photos/zaragozaantigua/34598416160/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25533, 'Vista del Ebro c.1863', '"Zaragoza. Vista del Ebro." Minimalista e irrepetible imagen del pretil que delimitaba la ribera y el paseo del Ebro, capturada desde leve altura en la zona de la antigua puerta y calle del Fin, durante una de las primeras visitas de Jean Laurent a la ciudad. En la margen izquierda, pasado el râ”śÂˇo, la arboleda de Macanaz y el desemboque de la acequia de desagâ”śâ•ťe de las Balsas de Ebro Viejo. Fuente visual: Archivo Ruiz-Vernacci (Fototeca del Patrimonio Histâ”śâ”‚rico) www.mcu.es', 1863, 1863, 1863, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65894200, -0.87963500, '0101000020E6100000BC57AD4CF825ECBFFDFA213658D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15870679830.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15870679830.webp', 'https://www.flickr.com/photos/zaragozaantigua/15870679830/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
